diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index c112fae35181..645882217c25 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4382,6 +4382,42 @@ Instruction *InstCombinerImpl::foldSelectICmp(CmpPredicate Pred, SelectInst *SI,

   return nullptr;
 }
+Instruction *InstCombinerImpl::foldSelectFCmp(CmpPredicate Pred, SelectInst *SI,
+                                              Value *RHS, const FCmpInst &I) {
+  auto SimplifyOp = [&](Value *Op, bool SelectCondIsTrue) -> Value * {
+    if (Value *Res = simplifyFCmpInst(Pred, Op, RHS, I.getFastMathFlags(), SQ))
+      return Res;
+    return nullptr;
+  };
+
+  ConstantInt *CI = nullptr;
+  Value *Op1 = SimplifyOp(SI->getOperand(1), true);
+  if (Op1)
+    CI = dyn_cast<ConstantInt>(Op1);
+
+  Value *Op2 = SimplifyOp(SI->getOperand(2), false);
+  if (Op2)
+    CI = dyn_cast<ConstantInt>(Op2);
+
+  bool Transform = false;
+  if (Op1 && Op2)
+    Transform = true;
+  else if ((Op1 || Op2) && SI->hasOneUse()) {
+    Transform = true;
+  } else if (CI && !CI->isZero()) {
+    Transform = replacedSelectWithOperand(SI, &I, Op1 ? 2 : 1);
+  }
+
+  if (Transform) {
+    if (!Op1)
+      Op1 = Builder.CreateFCmp(Pred, SI->getOperand(1), RHS, I.getName());
+    if (!Op2)
+      Op2 = Builder.CreateFCmp(Pred, SI->getOperand(2), RHS, I.getName());
+    return SelectInst::Create(SI->getOperand(0), Op1, Op2);
+  }
+
+  return nullptr;
+}

 // Returns whether V is a Mask ((X + 1) & X == 0) or ~Mask (-Pow2OrZero)
 static bool isMaskOrZero(const Value *V, bool Not, const SimplifyQuery &Q,
@@ -6790,7 +6826,7 @@ static bool isChainSelectCmpBranch(const SelectInst *SI) {
 /// compare, which usually happens in the combiner and test case
 /// select-cmp-br.ll checks for it.
 bool InstCombinerImpl::replacedSelectWithOperand(SelectInst *SI,
-                                                 const ICmpInst *Icmp,
+                                                 const CmpInst *Icmp,
                                                  const unsigned SIOpd) {
   assert((SIOpd == 1 || SIOpd == 2) && "Invalid select operand!");
   if (isChainSelectCmpBranch(SI) && Icmp->getPredicate() == ICmpInst::ICMP_EQ) {
@@ -8668,7 +8704,6 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       break;
     }
   }
-
   if (Instruction *R = foldFabsWithFcmpZero(I, *this))
     return R;

@@ -8781,6 +8816,10 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       return new FCmpInst(Pred, CanonLHS, CanonRHS, "", &I);
   }

+  if (auto *SI = dyn_cast<SelectInst>(Op0))
+    if (Instruction *NI = foldSelectFCmp(Pred, SI, Op1, I))
